  ('elementary-f29af906-moex-00758', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依耕地三七五減租條例規定，若承租人將耕地之一部轉租於他人時，下列敘述何者正確？', '["出租人得就該轉租部分終止租約", "出租人得就全部終止租約", "原訂租約轉租部分無效", "原訂租約全部無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00759', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '下列何者非屬土地公告徵收後之權利限制？', '["被徵收之土地或土地改良物自公告日起，除於公告前因繼承、強制執行或法院之判決而取得所有權或 他項權利，並於公告期間內申請登記者外，不得分割、合併、移轉或設定負擔", "土地權利人或使用人不得在該土地為建築改良物之新建、增建、改建", "土地權利人或使用人不得在該土地採取土石、變更地形或為農作改良物之增加種植", "共有分管之耕地，部分被徵收者，土地所有權人申請共有分割登記或應有部分分割移轉登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00760', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '甲因買賣而取得A土地所有權，其後發現Ａ土地底下蘊藏大量金礦。下列敘述，何者正確？', '["土地為甲所有，且金礦係由甲發現，故甲原始取得金礦所有權", "若A地為礦業用地，甲一律不得將A地轉賣移轉於B外國公司", "金礦雖由甲發現，但並不因甲為A地所有人而取得金礦所有權", "因土地為甲所有，故甲可無條件開採地下之金礦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00761', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '下列何種情形之土地所有權人，依法無申請徵收之公法上請求權？', '["徵收土地之殘餘部分面積過小，致不能為相當之使用者", "徵收區分地上權後之土地，因事業之興辦，致不能為相當之使用者", "土地徵用之徵用期間逾3年者", "經都市計畫指定為公共設施保留地者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00762', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '甲住新北市，因地價稅事件，不服臺北市稅捐稽徵處之處分，申請復查遭駁回，遂委由住居臺北市之執 業律師代理向臺北市政府提起訴願，其應自復查決定書送達之次日起幾日內提起訴願？', '["30日", "32日", "35日", "60日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00763', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依行政程序法規定，有關公示送達，下列敘述何者錯誤？', '["應為送達之處所不明", "公示送達應由行政機關保管送達之文書", "公示送達得由行政機關將文書刊登政府公報或新聞紙", "公示送達刊登政府公報或新聞紙者，自最後刊登之日起，經30日發生效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00764', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依行政程序法規定，有關聽證程序，下列敘述何者錯誤？', '["行政機關舉行聽證前，應以書面通知當事人及其他已知之利害關係人", "聽證期日之決定，應視事件之性質，預留相當期間", "行政機關得不問緣由依職權變更聽證場所", "聽證，除法律另有規定外，應公開以言詞為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
